S.push(
q('sql-b26','beg','Count departments',`Return the number of departments as <code>n</code>.`,`SELECT COUNT(*) AS n FROM departments;`,`SELECT COUNT(*) AS n FROM departments;`,false),
q('sql-b27','beg','Order by hire date',`Return <code>name, hire_date</code> ordered by hire date (earliest first).`,`SELECT name, hire_date FROM employees ORDER BY hire_date;`,`SELECT name, hire_date FROM employees ORDER BY hire_date;`,true),
q('sql-b28','beg','Oldest age',`Return the maximum age as <code>oldest</code>.`,`SELECT MAX(age) AS oldest FROM employees;`,`SELECT MAX(age) AS oldest FROM employees;`,false),
q('sql-b29','beg','Youngest age',`Return the minimum age as <code>youngest</code>.`,`SELECT MIN(age) AS youngest FROM employees;`,`SELECT MIN(age) AS youngest FROM employees;`,false),
q('sql-b30','beg','Name contains a',`Return <code>name</code> of employees whose name contains the letter <code>a</code> (lowercase).`,`SELECT name FROM employees WHERE name LIKE '%a%';`,`SELECT name FROM employees WHERE name LIKE '%a%';`,false),
q('sql-b31','beg','Count six-figure',`Return how many employees earn at least <code>100000</code> as <code>n</code>.`,`SELECT COUNT(*) AS n FROM employees WHERE salary >= 100000;`,`SELECT COUNT(*) AS n FROM employees WHERE salary >= 100000;`,false),
q('sql-b32','beg','Distinct ages',`Return the count of distinct ages as <code>n</code>.`,`SELECT COUNT(DISTINCT age) AS n FROM employees;`,`SELECT COUNT(DISTINCT age) AS n FROM employees;`,false),
q('sql-b33','beg','Big-budget departments',`Return department <code>name</code> where budget exceeds <code>500000</code>, ordered by name.`,`SELECT name FROM departments WHERE budget > 500000 ORDER BY name;`,`SELECT name FROM departments WHERE budget > 500000 ORDER BY name;`,true),
q('sql-b34','beg','Small projects',`Return project <code>name</code> with budget below <code>100000</code>, ordered by name.`,`SELECT name FROM projects WHERE budget < 100000 ORDER BY name;`,`SELECT name FROM projects WHERE budget < 100000 ORDER BY name;`,true),
q('sql-b35','beg','Heavy assignments',`Return <code>emp_id, project_id, hours</code> for assignments over 100 hours, ordered by hours desc then emp_id.`,`SELECT emp_id, project_id, hours FROM assignments WHERE hours > 100 ORDER BY hours DESC, emp_id;`,`SELECT emp_id, project_id, hours FROM assignments WHERE hours > 100 ORDER BY hours DESC, emp_id;`,true),
q('sql-i31','int','Total dept budget',`Return the sum of all department budgets as <code>total</code>.`,`SELECT SUM(budget) AS total FROM departments;`,`SELECT SUM(budget) AS total FROM departments;`,false),
q('sql-i32','int','Rounded avg salary',`Return the overall average salary rounded to a whole number as <code>avg_sal</code>.`,`SELECT ROUND(AVG(salary)) AS avg_sal FROM employees;`,`SELECT ROUND(AVG(salary)) AS avg_sal FROM employees;`,false),
q('sql-i33','int','Employees per location',`Return department <code>location</code> and headcount <code>n</code>, ordered by location.`,`SELECT d.location, COUNT(e.id) AS n FROM departments d JOIN employees e ON e.dept_id=d.id GROUP BY d.location ORDER BY d.location;`,`SELECT d.location, COUNT(e.id) AS n FROM departments d JOIN employees e ON e.dept_id=d.id GROUP BY d.location ORDER BY d.location;`,true),
q('sql-i34','int','Projects by status',`Return project <code>status</code> and count <code>n</code>, ordered by status.`,`SELECT status, COUNT(*) AS n FROM projects GROUP BY status ORDER BY status;`,`SELECT status, COUNT(*) AS n FROM projects GROUP BY status ORDER BY status;`,true),
q('sql-i35','int','Hours per project',`Return project <code>name</code> and total assigned <code>hours</code>, ordered by name.`,`SELECT p.name, SUM(a.hours) AS hours FROM projects p JOIN assignments a ON a.project_id=p.id GROUP BY p.name ORDER BY p.name;`,`SELECT p.name, SUM(a.hours) AS hours FROM projects p JOIN assignments a ON a.project_id=p.id GROUP BY p.name ORDER BY p.name;`,true),
q('sql-i36','int','Distinct managers',`Return distinct non-null <code>manager_id</code> values, ordered.`,`SELECT DISTINCT manager_id FROM employees WHERE manager_id IS NOT NULL ORDER BY manager_id;`,`SELECT DISTINCT manager_id FROM employees WHERE manager_id IS NOT NULL ORDER BY manager_id;`,true),
q('sql-i37','int','Hired in 2023',`Return <code>name</code> of employees hired in 2023, ordered by name.`,`SELECT name FROM employees WHERE strftime('%Y',hire_date)='2023' ORDER BY name;`,`SELECT name FROM employees WHERE strftime('%Y',hire_date)='2023' ORDER BY name;`,true),
q('sql-i38','int','Richest department',`Return the <code>name</code> of the department with the largest budget.`,`SELECT name FROM departments ORDER BY budget DESC LIMIT 1;`,`SELECT name FROM departments ORDER BY budget DESC LIMIT 1;`,true),
q('sql-i39','int','Average age',`Return the overall average age rounded to 1 decimal as <code>avg_age</code>.`,`SELECT ROUND(AVG(age),1) AS avg_age FROM employees;`,`SELECT ROUND(AVG(age),1) AS avg_age FROM employees;`,false),
q('sql-i40','int','Well-paid with dept',`Return employee <code>name</code> and department <code>name</code> as <code>dept</code> for salaries over 90000, ordered by employee name.`,`SELECT e.name, d.name AS dept FROM employees e JOIN departments d ON d.id=e.dept_id WHERE e.salary>90000 ORDER BY e.name;`,`SELECT e.name, d.name AS dept FROM employees e JOIN departments d ON d.id=e.dept_id WHERE e.salary>90000 ORDER BY e.name;`,true),
q('sql-a26','adv','3rd highest salary',`Return <code>name, salary</code> of the employee with the 3rd highest salary.`,`SELECT name, salary FROM employees ORDER BY salary DESC LIMIT 1 OFFSET 2;`,`SELECT name, salary FROM employees ORDER BY salary DESC LIMIT 1 OFFSET 2;`,false),
q('sql-a27','adv','Top of their dept',`Return <code>name</code> of employees whose salary equals the maximum in their department (correlated subquery), ordered by name.`,`SELECT name FROM employees e WHERE salary = (SELECT MAX(salary) FROM employees x WHERE x.dept_id=e.dept_id) ORDER BY name;`,`SELECT name FROM employees e WHERE salary = (SELECT MAX(salary) FROM employees x WHERE x.dept_id=e.dept_id) ORDER BY name;`,true),
q('sql-a28','adv','PERCENT_RANK',`Return <code>name</code> and salary percentile as <code>pr</code> via <code>PERCENT_RANK()</code> ordered by salary asc (rounded 2dp). Order by pr, name.`,`SELECT name, ROUND(PERCENT_RANK() OVER (ORDER BY salary),2) AS pr FROM employees ORDER BY pr, name;`,`SELECT name, ROUND(PERCENT_RANK() OVER (ORDER BY salary),2) AS pr FROM employees ORDER BY pr, name;`,true),
q('sql-a29','adv','FIRST_VALUE top earner',`For each employee return <code>name, dept_id</code> and the top earner's name in their dept as <code>top_earner</code> via <code>FIRST_VALUE</code>. Order by dept_id, salary desc.`,`SELECT name, dept_id, FIRST_VALUE(name) OVER (PARTITION BY dept_id ORDER BY salary DESC) AS top_earner FROM employees ORDER BY dept_id, salary DESC;`,`SELECT name, dept_id, FIRST_VALUE(name) OVER (PARTITION BY dept_id ORDER BY salary DESC) AS top_earner FROM employees ORDER BY dept_id, salary DESC;`,true),
q('sql-a30','adv','CUME_DIST',`Return <code>name</code> and cumulative distribution of salary as <code>cd</code> via <code>CUME_DIST()</code> (rounded 2dp), ordered by cd, name.`,`SELECT name, ROUND(CUME_DIST() OVER (ORDER BY salary),2) AS cd FROM employees ORDER BY cd, name;`,`SELECT name, ROUND(CUME_DIST() OVER (ORDER BY salary),2) AS cd FROM employees ORDER BY cd, name;`,true),
);

